// BL-1: forward the *exact* bytes ccmux must verify. We re-serialize once
// here and compute the HMAC over that same buffer, so the signature matches
// what ccmux's verifyGitHubSignature recomputes on its raw body.
//
// Set the n8n credential 'CCMUX_WEBHOOK_SECRET' in Settings → Environment.
const crypto = require('crypto');
const issue = $input.first().json.body.issue;
const payload = JSON.stringify({
  action: 'opened',
  issue: {
    number: issue.number,
    title: issue.title,
    body: issue.body || ''
  }
});
const secret = $env.CCMUX_WEBHOOK_SECRET || '';
let signature = '';
if (secret) {
  signature = 'sha256=' + crypto.createHmac('sha256', secret).update(payload).digest('hex');
}
return [{ json: { sessionName: `issue-${issue.number}`, payload, signature } }];
